public struct WhitelistEntry has copy, drop, store {
    can_send: bool,
    can_receive: bool,
}

public(package) fun add_to_whitelist<T>(treasury: &mut Treasury, addr: address) {
    let wl: &mut Table<address, WhitelistEntry> = dynamic_object_field::borrow_mut(
        &mut treasury.id,
        keys::whitelist_key<T>(),
    );
    assert!(!wl.contains(addr), EAlreadyWhitelisted);
    wl.add(addr, WhitelistEntry { can_send: true, can_receive: true });
}

public(package) fun set_whitelist_send<T>(
    treasury: &mut Treasury,
    addr: address,
    enabled: bool,
) {
    let wl: &mut Table<address, WhitelistEntry> = dynamic_object_field::borrow_mut(
        &mut treasury.id,
        keys::whitelist_key<T>(),
    );
    assert!(wl.contains(addr), ENotInWhitelist);
    wl[addr].can_send = enabled;
}

public struct WhitelistAdded<phantom T> has copy, drop {
